#include <stdio.h>
#define MOD 1000000007
int main() {
    int N, B, Q;
    scanf("%d %d", &N, &B);
    int trust[N][N] = {{0}};
    for (int i = 0; i < N; i++) {
        int ni;
        scanf("%d", &ni);
        for (int j = i + 1; j <= i + ni && j < N; j++) {
            trust[i][j] = 1;
        }
    }
    for (int k = 0; k < N; k++) {
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < N; j++) {
                trust[i][j] = (trust[i][j] + trust[i][k] * trust[k][j]) % MOD;
            }
        }
    }
    scanf("%d", &Q);
    for (int i = 0; i < Q; i++) {
        int S;
        scanf("%d", &S);
        printf("%d\n", trust[S - 1][B - 1]);
    }
    return 0;
}

